    def is_valid_move(self, from_pos, to_pos):
        x_from, y_from = from_pos[0], from_pos[1]
        x_to, y_to = to_pos[0], to_pos[1]

        piece = self.board[x_from][y_from]
        if not piece or piece == ' ':
