        if (x_from % 2 == 0 and (y_from + x_from) % 2 == 0) or (x_from % 2 == 1 and (y_from + x_from) % 2 == 1):
            return False

        if (piece == 'B' and y_to < y_from) or (piece == 'W' and y_to > y_from):
            return False

        if abs(y_to - y_from) != 1:
            return False

        # Capture check
        if abs(x_to - x_from) == 2:
            mid_x, mid_y = (x_from + x_to) // 2, (y_from + y_to) // 2
            if self.board[mid_x][mid_y] == 'B' or self.board[mid_x][mid_y] == 'W':
                return True
            else:
                return False

        return True

    def make_move(self, from_pos, to_pos):
        x_from, y_from = from_pos[0], from_pos[1]
        x_to, y_to = to_pos[0], to_pos[1]

        piece = self.board[x_from][y_from]
        if not self.is_valid_move(from_pos, to_pos):
            return False

        # Execute the move
        self.board[x_to][y_to] = piece
        self.board[x_from][y_from] = ' '

        # Capture logic
        if abs(x_to - x_from) == 2:
            mid_x, mid_y = (x_from + x_to) // 2, (y_from + y_to) // 2
            self.board[mid_x][mid_y] = ' '

        return True

    def is_game_over(self):
        # Check for win/draw conditions
        black_count = sum(row.count('B') for row in self.board)
        white_count = sum(row.count('W') for row in self.board)

        if black_count == 0:
            print("White wins!")
            return True
        elif white_count == 0:
            print("Black wins!")
            return True

        return False
